object Solution { def evaluate(expr: String): Int = { val tokens = tokenize(expr); var pos = 0; def parseExpr(): Int = { var value = parseTerm(); while (pos < tokens.length && (tokens(pos) == "+" || tokens(pos) == "-")) { val op = tokens(pos); pos += 1; val rhs = parseTerm(); value = if (op == "+") value + rhs else value - rhs }; value }; def parseTerm(): Int = { var value = parseFactor(); while (pos < tokens.length && (tokens(pos) == "*" || tokens(pos) == "/")) { val op = tokens(pos); pos += 1; val rhs = parseFactor(); value = if (op == "*") value * rhs else truncDiv(value, rhs) }; value }; def parseFactor(): Int = { if (tokens(pos) == "(") { pos += 1; val value = parseExpr(); pos += 1; value } else { val value = tokens(pos).toInt; pos += 1; value } }; parseExpr() }; private def tokenize(expr: String): Seq[String] = { val out = scala.collection.mutable.ArrayBuffer[String](); var i = 0; while (i < expr.length) { val ch = expr.charAt(i); if (ch == ' ') i += 1 else if (ch.isDigit) { val start = i; while (i < expr.length && expr.charAt(i).isDigit) i += 1; out += expr.substring(start, i) } else { out += ch.toString; i += 1 } }; out.toSeq }; private def truncDiv(a: Int, b: Int): Int = { val q = math.abs(a) / math.abs(b); if ((a < 0) == (b < 0)) q else -q } }
